import{_ as a,o as r,c as e,a2 as d}from"./chunks/framework.Cr-Z7ngm.js";const u=JSON.parse('{"title":"暗盘交易","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"ipo/grey-market-trading.md","filePath":"zh-CN/ipo/grey-market-trading.md"}'),i={name:"ipo/grey-market-trading.md"};function l(o,t,h,n,s,c){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="暗盘交易" tabindex="-1">暗盘交易 <a class="header-anchor" href="#暗盘交易" aria-label="Permalink to &quot;暗盘交易&quot;">​</a></h1><p>暗盘交易是在香港新股正式上市的前一天，提前参与新股买卖交易。仅港股主板上市的新股提供暗盘交易，创业板上市股票暂不支持。</p><p>暗盘交易不通过交易所系统，而是通过第三方香港券商提供的内部系统进行报价撮合。长桥证券接入的暗盘造市商为香港辉立证券（Phillip Securities HK）。暗盘价并不能全面反映市场需求，不应被视作该股的走势指标。</p><h2 id="交易时间" tabindex="-1">交易时间 <a class="header-anchor" href="#交易时间" aria-label="Permalink to &quot;交易时间&quot;">​</a></h2><p>正常交易日：新股正式上市前一个交易日 16:15 - 18:30<br> 半日市：暗盘当日为半日市时 14:15 - 16:30</p><h3 id="台风及黑色暴雨期间" tabindex="-1">台风及黑色暴雨期间 <a class="header-anchor" href="#台风及黑色暴雨期间" aria-label="Permalink to &quot;台风及黑色暴雨期间&quot;">​</a></h3><ul><li>中午 12:00 后始解除信号/警告：全日停止交易</li><li>中午 12:00 前解除信号/警告：暗盘交易如常于 16:15（半日市 14:15）开始</li><li>暗盘交易时段内发出信号/警告：暗盘交易如常进行至 18:30（半日市 16:30）</li></ul><h2 id="订单类型" tabindex="-1">订单类型 <a class="header-anchor" href="#订单类型" aria-label="Permalink to &quot;订单类型&quot;">​</a></h2><p>暗盘交易仅支持限价单。</p><h2 id="价格最小变动单位" tabindex="-1">价格最小变动单位 <a class="header-anchor" href="#价格最小变动单位" aria-label="Permalink to &quot;价格最小变动单位&quot;">​</a></h2><table tabindex="0"><thead><tr><th>股票价格（HKD）</th><th>最小变动单位（HKD）</th></tr></thead><tbody><tr><td>0.01 - 0.25</td><td>0.001</td></tr><tr><td>0.25 - 0.50</td><td>0.005</td></tr><tr><td>0.50 - 10.00</td><td>0.01</td></tr><tr><td>10.00 - 20.00</td><td>0.02</td></tr><tr><td>20.00 - 100.00</td><td>0.05</td></tr><tr><td>100.00 - 200.00</td><td>0.10</td></tr><tr><td>200.00 - 500.00</td><td>0.20</td></tr><tr><td>500.00 - 1,000.00</td><td>0.50</td></tr><tr><td>1,000.00 - 2,000.00</td><td>1.00</td></tr><tr><td>2,000.00 - 5,000.00</td><td>2.00</td></tr><tr><td>5,000.00 - 9,995.00</td><td>5.00</td></tr></tbody></table><h2 id="交易与交收机制" tabindex="-1">交易与交收机制 <a class="header-anchor" href="#交易与交收机制" aria-label="Permalink to &quot;交易与交收机制&quot;">​</a></h2><h3 id="交易机制" tabindex="-1">交易机制 <a class="header-anchor" href="#交易机制" aria-label="Permalink to &quot;交易机制&quot;">​</a></h3><p>暗盘实行 T+0 交易，暗盘中买入的股票可于当日暗盘卖出。</p><h3 id="交收机制" tabindex="-1">交收机制 <a class="header-anchor" href="#交收机制" aria-label="Permalink to &quot;交收机制&quot;">​</a></h3><p>暗盘成交的订单，交易日期为新股上市日期，交收日期为上市日起 T+2 个市场交易日。</p><p>示例：某新股暗盘在 2019 年 12 月 9 日（周一）进行，12 月 10 日（周二）正式上市，则交收日期为 12 月 12 日（周四）。</p><h2 id="新股延期或取消上市" tabindex="-1">新股延期或取消上市 <a class="header-anchor" href="#新股延期或取消上市" aria-label="Permalink to &quot;新股延期或取消上市&quot;">​</a></h2><ul><li>延期上市：已执行的交易视为有效，未完成的交易指示会被取消</li><li>取消上市：所有交易指示会被取消及无效</li><li>改变上市条款/条件：不影响暗盘交易，除非导致取消或延期上市</li></ul><p>暗盘为各券商独立的内部撮合系统，不同平台存在价差是正常现象；接入同一造市商的券商报价才会一致。长桥的暗盘报价与其他同样接入香港辉立的券商一致。</p>',20)])])}const b=a(i,[["render",l]]);export{u as __pageData,b as default};
